@GET('/user/:username', { schema })
export default class GetUserHandler extends RequestHandler {
  public handle(): Promise<{ username: string }> {
    const { username } = this.request.params as Record<string, string>;
    if (!users.has(username)) throw new UserError('USER_NOT_FOUND');

    return Promise.resolve({ username });
  }

  @ErrorHandler('USER_NOT_FOUND')
  public notExists(): void {
    this.reply.status(404).send({ message: 'User not found' });
  }
}

@DELETE('/user/:username')
export default class DeleteUserHandler extends RequestHandler {
  public handle(): void {
    const { username } = this.request.params as Record<string, string>;
    if (!users.has(username)) throw new UserError('USER_NOT_FOUND');

    users.delete(username);
    this.reply.status(204).send();
  }

  @ErrorHandler('USER_NOT_FOUND')
  public notExists(): void {
    this.reply.status(404).send({ message: 'User not found' });
  }
}

@POST('/user', { schema })
export default class CreateUserHandler extends RequestHandler {
  public handle(): void {
    const { username } = this.request.body as Record<string, string>;
    if (users.has(username)) throw new UserError('USER_ALREADY_EXISTS');

    this.reply.status(200).send(this.request.body);
  }

  @ErrorHandler('USER_ALREADY_EXISTS')
  userExists(): void {
    this.reply.status(422).send({ message: 'User already exists' });
  }
}

const prismaPlugin: FastifyPluginAsync = async (fastify, _options) => {
  const prisma = new PrismaClient({
    log: process.env.NODE_ENV === 'development' ? ['query', 'info', 'warn', 'error'] : ['error'],
  });

  // Connect to database
  await prisma.$connect();

  // Decorate Fastify instance with Prisma client
  fastify.decorate('prisma', prisma);

  // Graceful shutdown
  fastify.addHook('onClose', async () => {
    await prisma.$disconnect();
  });
};

app.setErrorHandler((error, request, reply) => {
  request.log.error({ err: error });

  const statusCode = error.statusCode || 500;
  const response = {
    success: false,
    error: {
      message: error.message || 'Internal Server Error',
      statusCode,
      requestId: request.id,
      timestamp: new Date().toISOString(),
    },
  };

  return reply.status(statusCode).send(response);
});

export abstract class BaseEndpoints {
  protected abstract _injectableAsyncService: InjectableAsyncService;
  protected abstract _injectableService: InjectableService;

  @GET('/sync')
  getSync(request: FastifyRequest, reply: FastifyReply): void {
    reply.send(this._injectableService.getMessage());
  }

  @GET('/async')
  async getAsync(): Promise<string> {
    return this._injectableAsyncService.getMessage();
  }
}

app.get('/user', { onRequest: [auth] }, async (request, reply) => {
  const user = await users?.findOne(
    { username: { $eq: request.user.username } },
    { projection: { password: 0, secret: 0 } },
  );

  const role = await roles?.findOne(
    { userId: { $ref: 'users', $id: user?._id } },
    { projection: { role: 1, permissions: 1 } },
  );

  return reply.send({ message: 'OK', ...user, ...role });
});

return function(target: object, propertyKey: string | symbol): void {
  // apply method if string or array of methods received, otherwise set all possible methods
  const method = typeof methods === 'string' || (Array.isArray(methods) && methods.length > 0) ? methods : httpMethods;

  Reflect.defineMetadata('fastify-resty:handler', { url, method, ...options }, target, propertyKey);

  if (Reflect.hasMetadata('fastify-resty:handlers', target)) {
    const handlers: Set<string> = Reflect.getMetadata('fastify-resty:handlers', target);
    handlers.add(propertyKey.toString());
  } else {
    Reflect.defineMetadata('fastify-resty:handlers', new Set([ propertyKey ]), target);
  }
}

