return function (target, propertyKey: string, parameterIndex?: number): void {
  let metadataKey;
  if (typeof propertyKey === 'undefined' && typeof parameterIndex === 'number') {
    metadataKey = 'fastify-resty:inject:constructor:model';
  } else if (typeof propertyKey === 'string' && typeof parameterIndex === 'undefined') {
    metadataKey = 'fastify-resty:inject:properties:model';
  }

  if (metadataKey) {
    const injectMap: Map<string | number, any> = Reflect.getMetadata(metadataKey, target) || new Map();
    injectMap.set(propertyKey || parameterIndex, { Entity, options });
    Reflect.defineMetadata(metadataKey, injectMap, target);
  }
}

for (const { name, propertyKey } of viaInject) {
  if (!injectables.has(name))
    throw new TypeError(`Invalid argument provided for "${className}.${String(propertyKey)}". Expected class annotated with @Service.`);

  Object.defineProperty(target, propertyKey, {
    value: (injectables.get(name) as InjectableService)[REGISTRABLE](classLoader, scope),
    enumerable: true,
    configurable: true,
    writable: true,
  });
}

const getAuthorizationBearer = (req: FastifyRequest) => {
  const { authorization } = req.headers
  if (!authorization) {
    throw httpErrors(401, 'No Authorization was found in request.headers')
  }

  const parts = authorization.split(' ')
  const [scheme, token] = parts

  if (parts.length !== 2 || !/^Bearer$/i.test(scheme)) {
    throw httpErrors(401, 'Format is Authorization: Bearer [token]')
  }

  return token
}

